from flask import Flask, redirect, url_for, request, session, render_template
import requests

app = Flask(__name__)
app.secret_key = 'your secret key'

client_id = 'your client id'
client_secret = 'your client secret'
authorization_server_url = 'https://your authorization server url.com/oauth2/authorize'
token_endpoint = 'https://your token endpoint.com/oauth2/token'

@app.route('/login')
def login():
    redirect_uri = url_for('callback', _external=True)
    return redirect(authorization_server_url + '?response_type=code&client_id=' + client_id +
                    '&redirect_uri=' + redirect_uri + '&scope=read')

@app.route('/callback')
def callback():
    code = request.args.get('code')
    headers = {'Content-Type': 'application/x-www-form-urlencoded'}
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': url_for('index', _external=True),
        'client_id': client_id,
        'client_secret': client_secret
    }
    response = requests.post(token_endpoint, headers=headers, data=data)
    if response.status_code == 200:
        token_response = response.json()
        session['access_token'] = token_response.get('access_token')
        return redirect(url_for('index'))
    else:
        return 'Error: {}'.format(response.text)

@app.route('/')
def index():
    if 'access_token' in session:
        return render_template('index.html')
    else:
        return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=True)